package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Objects;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {
  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetNumberToNumberStrategy_WithNonNullStrategy_ShouldSetFieldAndReturnThis() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    GsonBuilder returned = gsonBuilder.setNumberToNumberStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    // Use reflection to check private field numberToNumberStrategy
    Field field = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);
    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void testSetNumberToNumberStrategy_WithNullStrategy_ShouldThrowNullPointerException() {
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setNumberToNumberStrategy(null);
    });
    assertNotNull(thrown.getMessage());
  }
}
